SELECT S.GENERO FROM ESTAGIO E JOIN SERVIDOR S ON S.PK_SIAPE = E.FK_SIAPE WHERE E.DATA_INICIO >= (DATE('now', '-5 years')) AND LOWER(E.CAMPUS) LIKE LOWER('%aguas lindas%') AND LOWER(COALESCE(S.AREA_INGRESSO, S.AREA_INGRESSO_OG, '')) LIKE '%biologia geral%' AND S.GENERO IN ('MASCULINO','FEMININO') GROUP BY S.GENERO ORDER BY COUNT(*) DESC LIMIT 1